declare var mammoth: any;

type LayoutMode = 'evidence' | 'findings' | 'report' | 'split';
type ExportLanguage = 'en' | 'vi';

interface ExportState {
    isOpen: boolean;
    isPaused: boolean;
    isFinished: boolean;
    totalChunks: number;
    processedChunksCount: number;
    chunks: string[];
    results: string[];
    error: string | null;
    currentType: 'notes' | 'report' | 'evidence';
    targetLang: ExportLanguage;
}

interface UploadedFile {
    id: string;
    file: File;
    status: 'pending' | 'processing' | 'success' | 'error';
    error?: string;
    result?: string;
}

export default function App() {
    // --- SAV ENGINE (Secure Audit Vault) ---
    const vaultSentinel = useRef<{
        isRestoring: boolean;
        lastIntent: 'NONE' | 'NEW_SESSION' | 'RECALL' | 'USER_EDIT';
        lockUntil: number;
    }>({
        isRestoring: false,
        lastIntent: 'NONE',
        lockUntil: 0
    });

    // -- SESSION KEY: Forces re-render of complex child components on major state jumps
    const [sessionKey, setSessionKey] = useState(Date.now());

    // -- UI STATE --
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(420); 
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');

    // -- API & CONNECTIVITY --
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);
    const [isAutoCheckEnabled, setIsAutoCheckEnabled] = useState(false);
    const [editingKeyId, setEditingKeyId] = useState<string | null>(null);
    const [editLabelInput, setEditLabelInput] = useState("");

    // -- FEEDBACK --
    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const [lastSavedTime, setLastSavedTime] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false); 
    const [hasVaultData, setHasVaultData] = useState(false);

    // -- AUDIT CONTENT --
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [customStandards, setCustomStandards] = useState<StandardsData>({});

    // -- WORKFLOW --
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);
    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [isReportLoading, setIsReportLoading] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState("");
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState("");

    const [referenceClauseState, setReferenceClauseState] = useState<{
        isOpen: boolean;
        clause: Clause | null;
        fullText: { en: string; vi: string };
        isLoading: boolean;
    }>({
        isOpen: false,
        clause: null,
        fullText: { en: "", vi: "" },
        isLoading: false,
    });

    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 
    const [isDragging, setIsDragging] = useState(false);
    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");

    const [exportState, setExportState] = useState<ExportState>({
        isOpen: false,
        isPaused: false,
        isFinished: false,
        totalChunks: 0,
        processedChunksCount: 0,
        chunks: [],
        results: [],
        error: null,
        currentType: 'report',
        targetLang: 'en'
    });

    const [aiError, setAiError] = useState<string | null>(null);
    const [isErrorClosing, setIsErrorClosing] = useState(false);

    // -- REFS --
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });
    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);

    // -- COMPUTED --
    const allStandards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const hasEvidenceContent = useMemo(() => evidence.trim().length > SAV_CONFIG.MIN_MEANINGFUL_CHARS || uploadedFiles.length > 0, [evidence, uploadedFiles]);
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidenceContent;
    const isReadyToSynthesize = !isReportLoading && analysisResult && Object.values(selectedFindings).some(v => v);

    // Fix: Define activeKeyProfile
    const activeKeyProfile = useMemo(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);

    // Fix: Define getFindingColorClass helper
    const getFindingColorClass = (status: FindingStatus) => {
        switch (status) {
            case 'COMPLIANT': return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400';
            case 'NC_MAJOR': return 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400';
            case 'NC_MINOR': return 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400';
            case 'OFI': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400';
            case 'N_A': return 'bg-gray-100 text-gray-700 dark:bg-gray-900/30 dark:text-gray-400';
            default: return 'bg-gray-100 text-gray-700';
        }
    };

    const tabsList = [
        { id: 'evidence', label: '1. Evidence', icon: 'ScanText', colorClass: 'bg-blue-500', textClass: 'text-blue-600', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50 dark:bg-blue-950/30' }, 
        { id: 'findings', label: '2. Findings', icon: 'Wand2', colorClass: 'bg-purple-500', textClass: 'text-purple-600', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50 dark:bg-purple-950/30' }, 
        { id: 'report', label: '3. Report', icon: 'FileText', colorClass: 'bg-emerald-500', textClass: 'text-emerald-600', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50 dark:bg-emerald-950/30' }
    ];

    const currentTabConfig = tabsList.find(t => t.id === layoutMode) || tabsList[0];

    // --- SECURE AUDIT VAULT (SAV) CORE LOGIC ---

    // 1. Transactional Save Loop
    useEffect(() => {
        // SAFETY GUARD: If we are in restoration lock or component just mounted with empty state, BLOCK write.
        if (vaultSentinel.current.isRestoring || Date.now() < vaultSentinel.current.lockUntil) return;

        // ACCIDENTAL OVERWRITE PROTECTION:
        // If critical data is empty, only allow save IF user explicitly hit 'New Session'
        const isDataCurrentlyEmpty = evidence.trim().length === 0 && selectedClauses.length === 0;
        if (isDataCurrentlyEmpty && vaultSentinel.current.lastIntent !== 'NEW_SESSION') {
            return; // Skip auto-save to protect existing storage
        }

        setIsSaving(true);
        const saveTimer = setTimeout(() => {
            const sessionData = { 
                standardKey, auditInfo, selectedClauses, evidence, analysisResult, 
                selectedFindings, finalReportText, lastIntent: vaultSentinel.current.lastIntent
            };

            // ACTIVE SLOT
            localStorage.setItem(STORAGE_KEYS.ACTIVE_SESSION, JSON.stringify(sessionData));

            // VAULT SLOT (Archive if data is meaningful)
            if (evidence.length > SAV_CONFIG.MIN_MEANINGFUL_CHARS || selectedClauses.length > 2) {
                localStorage.setItem(STORAGE_KEYS.VAULT_ARCHIVE, JSON.stringify(sessionData));
                setHasVaultData(true);
            }

            setLastSavedTime(new Date().toLocaleTimeString());
            setIsSaving(false);

            // After successful save, if it was an intent, clear it unless it's NEW_SESSION
            if (vaultSentinel.current.lastIntent !== 'NEW_SESSION') {
                vaultSentinel.current.lastIntent = 'NONE';
            }
        }, SAV_CONFIG.DEBOUNCE_SAVE_MS);

        return () => clearTimeout(saveTimer);
    }, [standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText]);

    // 2. The Atomic Recall Operation
    const handleRecallVault = () => {
        const vaultDataRaw = localStorage.getItem(STORAGE_KEYS.VAULT_ARCHIVE) || localStorage.getItem(STORAGE_KEYS.ACTIVE_SESSION);
        if (!vaultDataRaw) {
            setToastMsg("Vault is empty. No data to restore.");
            return;
        }

        const confirmMsg = hasEvidenceContent 
            ? "Restore from Secure Vault? Current unsaved changes will be merged/overwritten."
            : "No active session. Restore previous data from Vault?";

        if (!confirm(confirmMsg)) return;

        try {
            // STEP A: ACTIVATE LOCK
            vaultSentinel.current.isRestoring = true;
            vaultSentinel.current.lockUntil = Date.now() + SAV_CONFIG.RESTORATION_LOCK_MS;
            vaultSentinel.current.lastIntent = 'RECALL';

            const data = JSON.parse(vaultDataRaw);

            // STEP B: HYDRATE STATE (Batched)
            if (data.standardKey) setStandardKey(data.standardKey);
            setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...(data.auditInfo || {}) });
            setSelectedClauses(data.selectedClauses || []);
            setEvidence(data.evidence || "");
            setAnalysisResult(data.analysisResult || null);
            setSelectedFindings(data.selectedFindings || {});
            setFinalReportText(data.finalReportText || null);

            // STEP C: CLEANUP & REFRESH
            setSessionKey(Date.now());
            setToastMsg("✅ Secure Vault Restored Successfully.");

            // STEP D: RELEASE LOCK after React cycle flushes
            setTimeout(() => {
                vaultSentinel.current.isRestoring = false;
            }, SAV_CONFIG.RESTORATION_LOCK_MS);

        } catch (e) {
            console.error("SAV Recall Failed", e);
            setToastMsg("❌ Vault Error: Data corrupted.");
            vaultSentinel.current.isRestoring = false;
        }
    };

    // 3. New Session with Auto-Vaulting
    const handleNewSession = () => {
        if (!confirm("Start New Session? Current data will be moved to Archive Vault.")) return;

        // STEP A: VAULT CURRENT DATA FIRST
        const currentData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
        localStorage.setItem(STORAGE_KEYS.VAULT_ARCHIVE, JSON.stringify(currentData));
        setHasVaultData(true);

        // STEP B: SET INTENT & RESET
        vaultSentinel.current.lastIntent = 'NEW_SESSION';
        vaultSentinel.current.lockUntil = Date.now() + 500; // Small lock for reset

        setStandardKey("ISO 9001:2015");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setEvidence("");
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setUploadedFiles([]);

        setSessionKey(Date.now());
        setLayoutMode('evidence');
        setToastMsg("✨ New Session Started. (Undo via Recall)");
    };

    // --- END SAV CORE ---

    // -- API POOL MGMT --
    const loadKeyData = (): ApiKeyProfile[] => {
        try {
            const stored = localStorage.getItem(STORAGE_KEYS.API_KEYS);
            const loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (!existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ id: `fixed_${index}_${Math.random().toString(36).substr(2, 5)}`, label: `Fixed Key ${index + 1}`, key: fixedKey, status: 'unknown', latency: 0, lastChecked: new Date().toISOString() });
                    hasChanges = true;
                }
            });
            if (hasChanges) localStorage.setItem(STORAGE_KEYS.API_KEYS, JSON.stringify(loadedKeys));
            const savedActiveId = localStorage.getItem(STORAGE_KEYS.ACTIVE_KEY_ID);
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) setActiveKeyId(savedActiveId);
            else if (loadedKeys.length > 0) setActiveKeyId(loadedKeys[0].id);
            return loadedKeys;
        } catch (e) { return []; }
    };

    useEffect(() => {
        // Initial Mount Logic
        const loadedKeys = loadKeyData();
        setApiKeys(loadedKeys);

        const storedVault = localStorage.getItem(STORAGE_KEYS.VAULT_ARCHIVE);
        if (storedVault) setHasVaultData(true);

        const storedScale = localStorage.getItem('iso_font_scale'); if (storedScale) setFontSizeScale(parseFloat(storedScale));
        const savedAutoCheck = localStorage.getItem('iso_auto_check'); if (savedAutoCheck !== null) setIsAutoCheckEnabled(savedAutoCheck === 'true');
        const savedDarkMode = localStorage.getItem('iso_dark_mode'); setIsDarkMode(savedDarkMode === null ? true : savedDarkMode === 'true');

        // Auto-restore attempt if active session exists and current state is fresh
        const activeData = localStorage.getItem(STORAGE_KEYS.ACTIVE_SESSION);
        if (activeData && !evidence && selectedClauses.length === 0) {
            try {
                const data = JSON.parse(activeData);
                if (data.evidence || data.selectedClauses?.length > 0) {
                    setStandardKey(data.standardKey || "ISO 9001:2015");
                    setAuditInfo(data.auditInfo || DEFAULT_AUDIT_INFO);
                    setSelectedClauses(data.selectedClauses || []);
                    setEvidence(data.evidence || "");
                }
            } catch(e) {}
        }
    }, []);

    // -- UI EFFECTS --
    useEffect(() => {
        document.documentElement.style.setProperty('--font-scale', fontSizeScale.toString());
        localStorage.setItem('iso_font_scale', fontSizeScale.toString());
        window.dispatchEvent(new Event('resize'));
    }, [fontSizeScale]);

    useEffect(() => {
        const root = document.documentElement;
        if (isDarkMode) { root.classList.add('dark'); document.body.classList.add('dark'); }
        else { root.classList.remove('dark'); document.body.classList.remove('dark'); }
        localStorage.setItem('iso_dark_mode', String(isDarkMode));
    }, [isDarkMode]);

    useEffect(() => {
        const updateTabs = () => { const activeIndex = tabsList.findIndex(t => t.id === layoutMode); const el = tabsRef.current[activeIndex]; if (el) { setTabStyle({ left: el.offsetLeft, width: el.offsetWidth, opacity: 1, color: tabsList[activeIndex].colorClass }); } };
        updateTabs(); setTimeout(updateTabs, 50); const observer = new ResizeObserver(updateTabs); if (tabsContainerRef.current) observer.observe(tabsContainerRef.current); return () => observer.disconnect();
    }, [layoutMode, sidebarWidth, fontSizeScale]); 

    // -- API EXECUTION WRAPPER --
    const executeWithSmartFailover = async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.status === 'valid' && b.status !== 'valid') return -1;
            if (a.id === activeKeyId) return -1;
            return a.latency - b.latency;
        });
        if (candidates.length === 0) throw new Error("API Key pool is exhausted. Please check settings.");
        let lastError: any;
        for (const profile of candidates) {
            const modelToUse = profile.activeModel || MODEL_HIERARCHY[0];
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                return await operation(profile.key, modelToUse);
            } catch (error: any) {
                console.warn(`Key ${profile.label} failed:`, error); lastError = error;
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded' } : k));
                else if (msg.includes("403") || msg.includes("invalid")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid' } : k));
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    };

    // Fix: Define handleOpenReferenceClause
    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState(p => ({ ...p, isOpen: true, clause, isLoading: true }));
        try {
            const text = await executeWithSmartFailover(async (key, model) => 
                fetchFullClauseText({ code: clause.code, title: clause.title }, allStandards[standardKey]?.name || "", key, model)
            );
            setReferenceClauseState(p => ({ ...p, fullText: text, isLoading: false }));
        } catch (e: any) {
            setReferenceClauseState(p => ({ ...p, isLoading: false }));
            setAiError("Failed to fetch clause text: " + e.message);
        }
    };

    // -- OCR LOGIC --
    const handleOcrUpload = async () => {
        const pending = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pending.length === 0) return;
        setIsOcrLoading(true); setLoadingMessage("Reading documents via Vision AI...");
        let processedCount = 0;
        for (const fileEntry of pending) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));
                let text = fileEntry.file.type === 'text/plain' ? await fileEntry.file.text() : await executeWithSmartFailover(async (key, model) => generateOcrContent("Extract all literal text.", await fileToBase64(fileEntry.file), fileEntry.file.type, key, model));
                if (text) {
                    setEvidence(prev => prev + `\n\n--- FILE: ${fileEntry.file.name} ---\n` + text);
                    setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                    processedCount++;
                }
            } catch (error: any) {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message } : f));
            }
        }
        setIsOcrLoading(false); setToastMsg(`Extracted text from ${processedCount} documents.`);
    };

    // -- ANALYSIS ENGINE (Turbo Parallel) --
    const handleAnalyze = async () => {
        if (!isReadyForAnalysis) return;
        setIsAnalyzeLoading(true); setAnalysisResult([]); setLayoutMode('findings'); 
        const healthyKeys = apiKeys.filter(k => k.status === 'valid').length;
        const CONCURRENCY = Math.max(2, Math.min(6, healthyKeys + 2));

        try {
            const allClauses = allStandards[standardKey].groups.flatMap(g => {
                const flat = (list: Clause[]): Clause[] => list.reduce((acc, c) => {
                    acc.push(c); if (c.subClauses) acc.push(...flat(c.subClauses)); return acc;
                }, [] as Clause[]);
                return flat(g.clauses);
            });
            const scope = selectedClauses.map(id => allClauses.find(c => c.id === id)).filter((c): c is Clause => !!c);

            for (let i = 0; i < scope.length; i += CONCURRENCY) {
                const batch = scope.slice(i, i + CONCURRENCY);
                setCurrentAnalyzingClause(batch.map(c => c.code).join(", "));
                setLoadingMessage(`Batch Analyzing [${i+1}-${Math.min(i+CONCURRENCY, scope.length)}/${scope.length}]...`);

                const results = await Promise.all(batch.map(async (clause) => {
                    const prompt = `Lead Auditor Task: Evaluate compliance for Clause [${clause.code}] ${clause.title}.\nCONTEXT: ${auditInfo.company}.\nEVIDENCE: """ ${evidence} """\nJSON Output: [{ clauseId: "${clause.id}", status: "COMPLIANT|NC_MAJOR|NC_MINOR|OFI", reason, suggestion, evidence, conclusion_report }]`;
                    try {
                        const resStr = await executeWithSmartFailover(async (key, model) => generateAnalysis(prompt, "Output JSON ONLY.", key, model));
                        return { clause, resStr };
                    } catch (e) { return { clause, error: true }; }
                }));

                setAnalysisResult(prev => {
                    const next = [...(prev || [])];
                    results.forEach(r => {
                        const parsed = cleanAndParseJSON(r.resStr || "");
                        if (parsed?.[0]) next.push(parsed[0]);
                    });
                    return next;
                });

                setSelectedFindings(prev => {
                    const next = { ...prev };
                    results.forEach(r => { if (r.resStr) next[r.clause.id] = true; });
                    return next;
                });
            }
        } catch (e: any) { setAiError(e.message); } finally { setIsAnalyzeLoading(false); setCurrentAnalyzingClause(""); }
    };

    const handleGenerateReport = async () => {
        if (!analysisResult) return;
        setIsReportLoading(true); setLayoutMode('report');
        try {
             const findings = analysisResult.filter(r => selectedFindings[r.clauseId]);
             const prompt = `Synthesize ISO Audit Report for ${auditInfo.company}. Data: ${JSON.stringify(findings)}. Template: ${reportTemplate || 'Standard'}.`;
             const text = await executeWithSmartFailover(async (key, model) => generateTextReport(prompt, "Lead Auditor Report Format.", key, model));
             setFinalReportText(text || "");
        } catch (e: any) { setAiError(e.message); } finally { setIsReportLoading(false); }
    };

    const handleOcrFiles = (files: File[]) => {
        const newFiles = files.map(f => ({ id: Math.random().toString(36).substr(2, 9), file: f, status: 'pending' as const }));
        setUploadedFiles(prev => [...prev, ...newFiles]);
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative overflow-hidden">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}

            {/* ERROR OVERLAY */}
            {aiError && (
                <div className={`fixed z-[9999] top-20 left-4 right-4 md:left-auto md:right-5 md:w-96 bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl rounded-r-xl p-4 animate-shake`}>
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2 text-red-600 font-bold"><Icon name="AlertCircle" size={20}/><span>System Error</span></div>
                        <button onClick={() => setAiError(null)} className="p-1 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-full"><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 mt-1">{aiError}</p>
                </div>
            )}

            {/* HEADER */}
            <header className="flex-shrink-0 px-4 md:px-6 py-0 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 z-[70] flex justify-between items-center h-16 shadow-sm">
                <div className="flex items-center gap-3 md:gap-5">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-gray-100 dark:hover:bg-slate-800 transition-all">
                        <Icon name="TDLogo" size={32} />
                    </button>
                    <div className="flex items-center gap-2">
                        <h1 className="text-sm md:text-lg font-black tracking-tight text-slate-900 dark:text-white uppercase">ISO Audit <span className="text-indigo-600">Pro</span></h1>
                        <span className="hidden md:inline px-2 py-0.5 rounded-md bg-indigo-50 dark:bg-indigo-900/30 text-[10px] font-bold text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-800">v{APP_VERSION}</span>
                    </div>
                </div>
                <div className="flex items-center gap-2 md:gap-3">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 rounded-xl text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-gray-100 dark:hover:bg-slate-800" title="Command Palette (Ctrl+K)">
                        <Icon name="Session6_Zap" size={20}/>
                    </button>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-xl text-slate-500 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-800 transition-all">
                        <Icon name={isDarkMode ? "Sun" : "Moon"} size={18}/>
                    </button>
                    <button onClick={() => setShowSettingsModal(true)} className="relative w-8 h-8 flex items-center justify-center">
                        {/* Fix: activeKeyProfile usage */}
                        <div className={`absolute inset-0 rounded-full opacity-20 animate-ping ${activeKeyProfile?.status === 'valid' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                        <div className={`relative w-2.5 h-2.5 rounded-full ring-2 ring-white dark:ring-slate-900 ${activeKeyProfile?.status === 'valid' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                    </button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                {/* SIDEBAR */}
                <Sidebar 
                    isOpen={isSidebarOpen} 
                    width={sidebarWidth} 
                    setWidth={setSidebarWidth} 
                    standards={allStandards} 
                    standardKey={standardKey} 
                    setStandardKey={setStandardKey} 
                    auditInfo={auditInfo} 
                    setAuditInfo={setAuditInfo} 
                    selectedClauses={selectedClauses} 
                    setSelectedClauses={setSelectedClauses} 
                    onAddNewStandard={() => {}} 
                    onUpdateStandard={(std) => setCustomStandards(p => ({...p, [standardKey]: std}))} 
                    onResetStandard={(k) => setCustomStandards(p => { const n={...p}; delete n[k]; return n; })} 
                    // Fix: handleOpenReferenceClause usage
                    onReferenceClause={handleOpenReferenceClause} 
                    showIntegrityModal={showIntegrityModal} 
                    setShowIntegrityModal={setShowIntegrityModal}
                />

                <div className={`flex-1 flex flex-col min-w-0 relative w-full transition-all duration-300 ease-soft ${currentTabConfig.bgSoft} border-t-4 ${currentTabConfig.borderClass}`}>

                    {/* SUB-HEADER TABS */}
                    <div className="flex-shrink-0 px-4 md:px-6 py-3 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center gap-3">
                        <div className="flex-1 min-w-0">
                            <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-100 dark:bg-slate-950 p-1 rounded-xl w-full">
                                <div className={`absolute top-1 bottom-1 shadow-sm rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${tabStyle.color}`} style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity }} />
                                {tabsList.map((tab, idx) => (
                                    <button key={tab.id} ref={el => { tabsRef.current[idx] = el; }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2 rounded-lg text-xs md:text-sm font-bold transition-colors ${layoutMode === tab.id ? 'text-white' : 'text-slate-500 dark:text-slate-400'}`}>
                                        <Icon name={tab.icon} size={16}/> 
                                        <span className="hidden md:inline">{tab.label}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                            {/* RECALL BUTTON - SECURE VAULT ACCESS */}
                            <button 
                                onClick={handleRecallVault} 
                                className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all active:scale-95 border ${hasVaultData ? 'bg-emerald-500 text-white shadow-emerald-500/20' : 'bg-white dark:bg-slate-800 text-slate-400'}`} 
                                title="Recall from Secure Audit Vault"
                            >
                                <Icon name="History" size={18}/>
                                <span className="hidden xl:inline text-xs font-bold">Recall Vault</span>
                            </button>
                            <button onClick={handleNewSession} className="h-10 w-10 md:w-auto md:px-4 bg-amber-500 text-white rounded-xl flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg shadow-amber-500/20" title="New Session (Archive Current)">
                                <Icon name="Plus" size={18}/>
                                <span className="hidden md:inline text-xs font-bold">New</span>
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative p-2 md:p-4">
                        {/* EVIDENECE */}
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className={`flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border overflow-hidden flex flex-col relative ${isDragging ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-gray-100 dark:border-transparent'}`} onDragOver={e=>{e.preventDefault(); setIsDragging(true);}} onDragLeave={()=>setIsDragging(false)} onDrop={e=>{e.preventDefault(); setIsDragging(false); handleOcrFiles(Array.from(e.dataTransfer.files));}}>
                                    <textarea className="flex-1 w-full p-4 bg-transparent outline-none text-sm leading-relaxed dark:text-slate-200 font-medium" placeholder="Paste evidence or drag documents (PDF, JPG, PNG) here..." value={evidence} onChange={e=>setEvidence(e.target.value)} />
                                    {isOcrLoading && <AINeuralLoader message={loadingMessage} />}
                                </div>

                                {uploadedFiles.length > 0 && (
                                    <div className="flex gap-2 p-2 bg-gray-50 dark:bg-slate-800 rounded-2xl overflow-x-auto">
                                        {uploadedFiles.map(f => (
                                            <div key={f.id} className="relative w-20 h-20 bg-white dark:bg-slate-700 rounded-lg flex-shrink-0 border flex items-center justify-center overflow-hidden">
                                                {f.status === 'processing' ? <Icon name="Loader" className="animate-spin text-indigo-500"/> : f.status === 'success' ? <Icon name="CheckCircle2" className="text-emerald-500"/> : <Icon name="FileText" className="text-slate-400"/>}
                                                <button onClick={() => setUploadedFiles(p => p.filter(x => x.id !== f.id))} className="absolute top-0 right-0 p-0.5 bg-red-500 text-white rounded-bl-lg"><Icon name="X" size={10}/></button>
                                            </div>
                                        ))}
                                        <button onClick={handleOcrUpload} className="w-20 h-20 bg-indigo-600 text-white rounded-lg flex flex-col items-center justify-center gap-1 active:scale-95 transition-all">
                                            <Icon name="ScanText" size={20}/>
                                            <span className="text-[10px] font-bold">Process</span>
                                        </button>
                                    </div>
                                )}

                                <div className="flex justify-end gap-3 pt-2">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} className={`px-6 h-[52px] rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${isReadyForAnalysis ? 'btn-shrimp active:scale-95' : 'bg-gray-200 dark:bg-slate-800 text-slate-400'}`}>
                                        {isAnalyzeLoading ? <SparkleLoader/> : <Icon name="Wand2"/>}
                                        <span>ANALYZE</span>
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* FINDINGS */}
                        {layoutMode === 'findings' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 overflow-y-auto custom-scrollbar p-1" ref={findingsContainerRef}>
                                    {isAnalyzeLoading && (
                                        <div className="h-full flex flex-col items-center justify-center">
                                            <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
                                            <p className="text-sm font-bold text-slate-500">{loadingMessage}</p>
                                            <p className="text-[10px] text-slate-400 font-mono mt-1">{currentAnalyzingClause}</p>
                                        </div>
                                    )}
                                    {analysisResult && (
                                        <div className={findingsViewMode === 'matrix' ? "grid grid-cols-1 md:grid-cols-2 gap-4" : "space-y-4"}>
                                            {analysisResult.map((res, idx) => (
                                                <div key={idx} className={`bg-white dark:bg-slate-900 p-4 rounded-2xl border ${selectedFindings[res.clauseId] ? 'border-indigo-500 ring-2 ring-indigo-500/10' : 'border-gray-100 dark:border-slate-800'}`} onClick={() => setSelectedFindings(p=>({...p, [res.clauseId]: !p[res.clauseId]}))}>
                                                    <div className="flex items-center justify-between mb-2">
                                                        <span className="text-xs font-black bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 px-2 py-1 rounded">{res.clauseId}</span>
                                                        {/* Fix: getFindingColorClass usage */}
                                                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${getFindingColorClass(res.status as FindingStatus)}`}>{res.status}</span>
                                                    </div>
                                                    <p className="text-sm font-bold text-slate-800 dark:text-slate-200">{res.reason}</p>
                                                    <p className="text-[11px] text-slate-500 mt-2 bg-gray-50 dark:bg-slate-950 p-2 rounded italic">Evidence: {res.evidence}</p>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                                <div className="flex justify-between items-center bg-white dark:bg-slate-900 p-2 rounded-2xl border border-gray-100 dark:border-slate-800">
                                    <div className="flex gap-2">
                                        <button onClick={()=>setFindingsViewMode('list')} className={`p-2 rounded-lg ${findingsViewMode === 'list' ? 'bg-indigo-50 text-indigo-600' : ''}`}><Icon name="LayoutList"/></button>
                                        <button onClick={()=>setFindingsViewMode('matrix')} className={`p-2 rounded-lg ${findingsViewMode === 'matrix' ? 'bg-indigo-50 text-indigo-600' : ''}`}><Icon name="Grid"/></button>
                                    </div>
                                    <button onClick={handleGenerateReport} className="px-6 h-10 bg-emerald-500 text-white rounded-xl font-bold text-xs active:scale-95 transition-all">GENERATE REPORT</button>
                                </div>
                            </div>
                        )}

                        {/* REPORT */}
                        {layoutMode === 'report' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 bg-white dark:bg-slate-900 rounded-3xl border border-gray-100 dark:border-slate-800 p-4 relative">
                                    <textarea className="w-full h-full bg-transparent outline-none text-sm font-mono dark:text-slate-200" value={finalReportText || ""} onChange={e=>setFinalReportText(e.target.value)} />
                                    {isReportLoading && <AINeuralLoader message="Synthesizing final report..." />}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </main>

            {/* MODALS */}
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={()=>setIsCmdPaletteOpen(false)} actions={[]} onSelectAction={()=>{}} />
            <ReleaseNotesModal isOpen={showAboutModal} onClose={()=>setShowAboutModal(false)} />
            <ReferenceClauseModal isOpen={referenceClauseState.isOpen} onClose={()=>setReferenceClauseState(p=>({...p, isOpen:false}))} clause={referenceClauseState.clause} standardName={allStandards[standardKey]?.name || ""} fullText={referenceClauseState.fullText} isLoading={referenceClauseState.isLoading} onInsert={(t)=>setEvidence(p=>p+"\n"+t)} />

            <Modal isOpen={showSettingsModal} title="Secure Neural Pool" onClose={()=>setShowSettingsModal(false)}>
                <div className="space-y-4">
                    <h4 className="text-xs font-bold text-slate-400 uppercase">API Key Management</h4>
                    {apiKeys.map(k => (
                        <div key={k.id} className="flex items-center justify-between p-3 bg-gray-50 dark:bg-slate-800 rounded-xl">
                            <div className="flex items-center gap-3">
                                <div className={`w-2 h-2 rounded-full ${k.status === 'valid' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                                <span className="text-xs font-bold">{k.label}</span>
                            </div>
                            <span className="text-[10px] font-mono text-slate-400">{k.key.substring(0, 10)}...</span>
                        </div>
                    ))}
                    <div className="pt-4 border-t flex flex-col gap-2">
                        <button onClick={() => { localStorage.clear(); location.reload(); }} className="p-3 bg-red-50 text-red-600 rounded-xl text-xs font-bold hover:bg-red-100">HARD RESET (Purge Everything)</button>
                        <p className="text-[9px] text-slate-400 text-center italic">App Version: {APP_VERSION} | Build: {BUILD_TIMESTAMP}</p>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

