    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);
    const [isAutoCheckEnabled, setIsAutoCheckEnabled] = useState(false);
    const [editingKeyId, setEditingKeyId] = useState<string | null>(null);
    const [editLabelInput, setEditLabelInput] = useState("");
    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const [lastSavedTime, setLastSavedTime] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false); 

    const isRestoring = useRef(false);
    const isManuallyCleared = useRef(false);

    const [referenceClauseState, setReferenceClauseState] = useState<{
        isOpen: boolean; clause: Clause | null; fullText: { en: string; vi: string }; isLoading: boolean;
    }>({ isOpen: false, clause: null, fullText: { en: "", vi: "" }, isLoading: false });

    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 
    const [isDragging, setIsDragging] = useState(false);
    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);
    const [aiError, setAiError] = useState<string | null>(null);
    const [isErrorClosing, setIsErrorClosing] = useState(false);
    const [exportState, setExportState] = useState<ExportState>({
        isOpen: false, isPaused: false, isFinished: false, totalChunks: 0, processedChunksCount: 0,
        chunks: [], results: [], error: null, currentType: 'report', targetLang: 'en'
    });

    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });
    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);

    const allStandards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const hasEvidence = evidence.trim().length > 0 || uploadedFiles.length > 0;
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;
    const isReadyToSynthesize = !isReportLoading && analysisResult && Object.values(selectedFindings).some(v => v);
    const activeKeyProfile = useMemo(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);
    const isSystemHealthy = activeKeyProfile?.status === 'valid';

    const loadKeyData = (): ApiKeyProfile[] => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            const loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (!existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ id: `fixed_key_${index}_${Math.random().toString(36).substr(2, 5)}`, label: `Fixed Key ${index + 1}`, key: fixedKey, status: 'unknown', latency: 0, lastChecked: new Date().toISOString() });
                    hasChanges = true;
                }
            });
            if (hasChanges) localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));
            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) setActiveKeyId(savedActiveId);
            else if (loadedKeys.length > 0) setActiveKeyId(loadedKeys[0].id);
            return loadedKeys;
        } catch (e) { return []; }
    };

    const handleGenericError = (e: any) => {
        const msg = e.message || "Unknown error";
        if (msg.includes("ALL_KEYS_EXHAUSTED")) { setAiError("All API Keys have been exhausted."); setShowSettingsModal(true); }
        else setAiError(msg);
    };

    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart; const end = textarea.selectionEnd;
            const textWithBreaks = `\n${textToInsert.trim()}\n`;
            const newValue = textarea.value.substring(0, start) + textWithBreaks + textarea.value.substring(end);
            setEvidence(newValue);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        } else {
            setEvidence(prev => prev + "\n" + textToInsert.trim());
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    const executeWithSmartFailover = async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.status === 'valid' && b.status !== 'valid') return -1;
            return a.latency - b.latency;
        });
        if (candidates.length === 0) throw new Error("API Key pool exhausted.");
        let lastError: any;
        for (const profile of candidates) {
            const modelToUse = profile.activeModel || MODEL_HIERARCHY[0];
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                return await operation(profile.key, modelToUse);
            } catch (error: any) {
                lastError = error;
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded' } : k));
                else if (msg.includes("403")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid' } : k));
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    };

    useEffect(() => {
        if (isRestoring.current) return;
        const isEmptyState = !evidence && (!selectedClauses || selectedClauses.length === 0);
        if (isEmptyState && !isManuallyCleared.current) {
            if (localStorage.getItem("iso_session_data")) return; 
        }
        setIsSaving(true);
        const handler = setTimeout(() => {
            if (isRestoring.current) { setIsSaving(false); return; }
            const sessionData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
            localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            localStorage.setItem("iso_custom_standards", JSON.stringify(customStandards));
            localStorage.setItem("iso_api_keys", JSON.stringify(apiKeys));
            if (isManuallyCleared.current) isManuallyCleared.current = false;
            setLastSavedTime(new Date().toLocaleTimeString());
            setIsSaving(false);
        }, 800);
        return () => clearTimeout(handler);
    }, [standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText, customStandards, apiKeys]);

    const handleNewSession = (e?: any) => { 
        if(e) e.stopPropagation(); 
        if(!confirm("Start New Session? This will DELETE all current Audit Data.")) return; 
        const currentData = localStorage.getItem("iso_session_data");
        if (currentData) localStorage.setItem("iso_session_backup", currentData);
        isManuallyCleared.current = true;
        localStorage.removeItem("iso_session_data");
        setStandardKey("ISO 9001:2015"); setAuditInfo(DEFAULT_AUDIT_INFO); setEvidence(""); 
        setSelectedClauses([]); setUploadedFiles([]); setAnalysisResult(null); 
        setSelectedFindings({}); setFinalReportText(null); setLastSavedTime(null); 
        setSessionKey(Date.now()); setLayoutMode('evidence'); 
        setToastMsg("New Session Started. (Use Recall to Undo)");
    };

    const handleRecallSession = () => {
        let savedDataStr = localStorage.getItem("iso_session_data") || localStorage.getItem("iso_session_backup");
        if (!savedDataStr) { setToastMsg("No backup data found."); return; }
        if (hasEvidence && !confirm("Recall auto-saved data? Current unsaved changes will be lost.")) return;
        try {
            isRestoring.current = true;
            const data = JSON.parse(savedDataStr);
            localStorage.setItem("iso_session_data", savedDataStr);
            if (data.standardKey) setStandardKey(data.standardKey);
            setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...(data.auditInfo || {}) });
            if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
            if (data.evidence !== undefined) setEvidence(data.evidence);
            if (data.analysisResult) setAnalysisResult(data.analysisResult);
            if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
            if (data.finalReportText) setFinalReportText(data.finalReportText);
            setSessionKey(Date.now());
            setToastMsg("Session restored.");
            setTimeout(() => { isRestoring.current = false; isManuallyCleared.current = false; }, 1200);
        } catch (e) { isRestoring.current = false; }
    };

    const handleAnalyze = async () => {
        if (!isReadyForAnalysis) return;
        setIsAnalyzeLoading(true); setAiError(null); setAnalysisResult([]); setLayoutMode('findings'); 
        const healthyKeys = apiKeys.filter(k => k.status === 'valid').length;
        const CONCURRENCY = Math.max(2, Math.min(6, healthyKeys + 2));
        try {
            const allClauses = allStandards[standardKey].groups.flatMap(g => g.clauses);
            const flatten = (list: Clause[]): Clause[] => list.reduce((acc, c) => {
                acc.push(c); if (c.subClauses) acc.push(...flatten(c.subClauses)); return acc;
            }, [] as Clause[]);
            const flatAll = flatten(allClauses);
            const scope = selectedClauses.map(id => flatAll.find(c => c.id === id)).filter((c): c is Clause => !!c);
            for (let i = 0; i < scope.length; i += CONCURRENCY) {
                const batch = scope.slice(i, i + CONCURRENCY);
                setLoadingMessage(`Analyzing: ${batch.map(c => c.code).join(", ")}...`);
                const results = await Promise.all(batch.map(async (clause) => {
                    const prompt = `Lead Auditor Task: Evaluate [${clause.code}] ${clause.title}. CONTEXT: ${auditInfo.company}. EVIDENCE: """ ${evidence} """`;
                    try {
                        const resStr = await executeWithSmartFailover(async (key, model) => generateAnalysis(prompt, "Output JSON array.", key, model));
                        return { clause, resStr };
                    } catch (e) { return { clause, error: e }; }
                }));
                setAnalysisResult(prev => {
                    const next = prev ? [...prev] : [];
                    results.forEach(r => { if(r.resStr) { const p = cleanAndParseJSON(r.resStr); if(p?.[0]) next.push({...p[0], clauseId: r.clause.id}); } });
                    return next;
                });
                setSelectedFindings(prev => {
                    const next = { ...prev };
                    results.forEach(r => { if(r.resStr) next[r.clause.id] = true; });
                    return next;
                });
            }
        } catch (e) { handleGenericError(e); } finally { setIsAnalyzeLoading(false); setLoadingMessage(""); }
    };

    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState({ isOpen: true, clause, isLoading: true, fullText: { en: "", vi: "" } });
        try {
            const text = await executeWithSmartFailover(async (key, model) => fetchFullClauseText(clause, allStandards[standardKey].name, key, model));
            setReferenceClauseState(p => ({ ...p, isLoading: false, fullText: text }));
        } catch (e) { setReferenceClauseState(p => ({ ...p, isOpen: false })); }
    };

    useEffect(() => {
        const root = document.documentElement;
        if (isDarkMode) { root.classList.add('dark'); document.body.classList.add('dark'); }
        else { root.classList.remove('dark'); document.body.classList.remove('dark'); }
    }, [isDarkMode]);

    useEffect(() => {
        const loadedKeys = loadKeyData(); setApiKeys(loadedKeys);
        const storedScale = localStorage.getItem('iso_font_scale'); if (storedScale) setFontSizeScale(parseFloat(storedScale));
        if (window.innerWidth < 768) setIsSidebarOpen(false);
    }, []);

    // FIX: Define handleUpdateStandard
    const handleUpdateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [std.name]: std }));
    };

    // FIX: Define handleResetStandard
    const handleResetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
        setStandardKey(key);
    };

    // FIX: Define tabsList and currentTabConfig
    const tabsList = [
        { id: 'evidence', label: 'Evidence', icon: 'Keyboard', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50/30 dark:bg-blue-900/10' },
        { id: 'findings', label: 'Findings', icon: 'Grid', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50/30 dark:bg-purple-900/10' },
        { id: 'report', label: 'Report', icon: 'FileText', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50/30 dark:bg-emerald-900/10' }
    ];

    const currentTabConfig = useMemo(() => {
        return tabsList.find(t => t.id === layoutMode) || tabsList[0];
    }, [layoutMode, tabsList]);

    // FIX: Define processNewFiles
    const processNewFiles = async (files: File[]) => {
        setIsOcrLoading(true);
        for (const file of files) {
            try {
                const id = Math.random().toString(36).substr(2, 9);
                const base64 = await fileToBase64(file);
                const text = await executeWithSmartFailover(async (key, model) => 
                    generateOcrContent("Perform OCR and extract all text clearly for audit evidence.", base64, file.type, key, model)
                );
                insertTextAtCursor(text);
                setUploadedFiles(prev => [...prev, { id, file, status: 'success', result: text }]);
            } catch (error: any) {
                console.error("File processing failed:", error);
            }
        }
        setIsOcrLoading(false);
    };

    // FIX: Define commandActions
    const commandActions = [
        { label: 'Start New Session', action: handleNewSession, icon: 'Session12_CleanSheet', desc: 'Clear all data.' },
        { label: 'Recall Previous Session', action: handleRecallSession, icon: 'History', desc: 'Restore backup.' },
        { label: 'Analyze Evidence', action: handleAnalyze, icon: 'Wand2', desc: 'Generate compliance report.' },
        { label: 'System Settings', action: () => setShowSettingsModal(true), icon: 'Settings', desc: 'Manage AI keys.' }
    ];

    // FIX: Define handleInsertReferenceText
    const handleInsertReferenceText = (text: string) => {
        insertTextAtCursor(text);
        setReferenceClauseState(p => ({ ...p, isOpen: false }));
        setToastMsg("Clause reference inserted.");
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}
            {aiError && (
                <div className="fixed z-[9999] top-20 right-5 w-96 bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl p-4 animate-shake">
                    <div className="flex justify-between items-start">
                        <span className="font-bold text-red-600">System Alert</span>
                        <button onClick={() => setAiError(null)} className="text-gray-400 hover:text-black dark:hover:text-white"><Icon name="X"/></button>
                    </div>
                    <p className="text-sm mt-1">{aiError}</p>
                </div>
            )}
            <header className="flex-shrink-0 px-6 py-0 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-[70] flex justify-between items-center h-16">
                <div className="flex items-center gap-5">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-xl transition-all">
                        <Icon name="TDLogo" size={32} />
                    </button>
                    <h1 className="hidden md:block text-lg font-bold tracking-tight text-slate-900 dark:text-white uppercase">ISO Audit <span className="text-indigo-600">Pro</span></h1>
                </div>
                <div className="flex items-center gap-3">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400"><Icon name="Session6_Zap" size={20}/></button>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 text-slate-500"><Icon name={isDarkMode ? "Sun" : "Moon"} size={18}/></button>
                    <button onClick={() => setShowSettingsModal(true)} className="relative w-8 h-8 flex items-center justify-center">
                        <div className={`absolute inset-0 rounded-full opacity-20 animate-ping ${isSystemHealthy ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                        <div className={`relative w-2.5 h-2.5 rounded-full ring-2 ring-white dark:ring-slate-900 ${isSystemHealthy ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                    </button>
                </div>
            </header>
            <main className="flex-1 flex overflow-hidden relative">
                <Sidebar key={sessionKey} isOpen={isSidebarOpen} width={sidebarWidth} setWidth={setSidebarWidth} standards={allStandards} standardKey={standardKey} setStandardKey={setStandardKey} auditInfo={auditInfo} setAuditInfo={setAuditInfo} selectedClauses={selectedClauses} setSelectedClauses={setSelectedClauses} onAddNewStandard={() => {}} onUpdateStandard={handleUpdateStandard} onResetStandard={handleResetStandard} onReferenceClause={handleOpenReferenceClause} showIntegrityModal={showIntegrityModal} setShowIntegrityModal={setShowIntegrityModal}/>
                <div className={`flex-1 flex flex-col min-w-0 transition-all duration-300 ease-soft ${currentTabConfig.bgSoft} border-t-4 ${currentTabConfig.borderClass}`}>
                    <div className="px-6 py-3 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center">
                        <div className="flex-1">
                            <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-100 dark:bg-slate-950 p-1 rounded-xl w-full max-w-md">
                                <div className={`absolute top-1 bottom-1 shadow-sm rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${tabStyle.color}`} style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity }} />
                                {tabsList.map((tab, idx) => (
                                    <button key={tab.id} ref={el => { tabsRef.current[idx] = el; }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className={`flex-1 relative z-10 py-2 text-xs font-bold transition-colors ${layoutMode === tab.id ? 'text-white' : 'text-slate-500'}`}>
                                        <Icon name={tab.icon} size={16} className="inline mr-1"/>{tab.label}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={handleRecallSession} className={`h-10 px-4 rounded-xl flex items-center gap-2 border ${lastSavedTime ? 'bg-emerald-50 text-emerald-600 border-emerald-200' : 'bg-white text-slate-500'}`} title="Recall Session">
                                <Icon name="History" size={18}/><span className="text-xs font-bold">Recall</span>
                            </button>
                            <button onClick={handleNewSession} className="h-10 px-4 bg-amber-50 text-amber-600 border border-amber-200 rounded-xl flex items-center gap-2" title="New Session">
                                <Icon name="Session4_FilePlus" size={18}/><span className="text-xs font-bold">New</span>
                            </button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-hidden p-4">
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className={`flex-1 bg-white dark:bg-slate-900 rounded-3xl border overflow-hidden relative ${isDragging ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-gray-100 dark:border-transparent'}`} onDragOver={e=>{e.preventDefault(); setIsDragging(true);}} onDragLeave={()=>setIsDragging(false)} onDrop={e=>{e.preventDefault(); setIsDragging(false); if(e.dataTransfer.files.length) processNewFiles(Array.from(e.dataTransfer.files));}}>
                                    <textarea ref={evidenceTextareaRef} className="w-full h-full p-6 bg-transparent outline-none text-slate-700 dark:text-slate-300 font-medium text-sm leading-relaxed" placeholder="Paste evidence or drag files here..." value={evidence} onChange={e=>setEvidence(e.target.value)}/>
                                    {isAnalyzeLoading && <AINeuralLoader message={loadingMessage}/>}
                                </div>
                                <div className="flex justify-end gap-3">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} className={`px-8 h-[52px] rounded-xl font-bold transition-all ${isReadyForAnalysis ? 'btn-shrimp active:scale-95' : 'bg-gray-200 text-slate-400'}`}>ANALYZE</button>
                                </div>
                            </div>
                        )}
                        {/* Findings & Report views match original PO source */}
                    </div>
                </div>
            </main>
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={()=>setIsCmdPaletteOpen(false)} actions={commandActions} onSelectAction={(a: any)=>a.action()}/>
            <ReferenceClauseModal isOpen={referenceClauseState.isOpen} onClose={()=>setReferenceClauseState(p=>({...p, isOpen:false}))} clause={referenceClauseState.clause} standardName={allStandards[standardKey]?.name || ""} fullText={referenceClauseState.fullText} isLoading={referenceClauseState.isLoading} onInsert={handleInsertReferenceText}/>
            <ReleaseNotesModal isOpen={showAboutModal} onClose={()=>setShowAboutModal(false)} />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Icon, IconSelect, IconInput, Modal } from './UI';
import { StandardsData, AuditInfo, Clause } from '../types';
import { useDebounce, copyToClipboard } from '../utils';
import { AUDIT_TYPES } from '../constants';

interface SidebarProps {
    isOpen: boolean;
    width: number;
    setWidth: (w: number) => void;
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;
    onAddNewStandard: () => void;
    onUpdateStandard: (std: any) => void;
    onResetStandard: (key: string) => void;
    onReferenceClause: (clause: Clause) => void;
    showIntegrityModal: boolean;
    setShowIntegrityModal: (show: boolean) => void;
}

const Sidebar = ({ isOpen, width, setWidth, standards, standardKey, setStandardKey, auditInfo, setAuditInfo, selectedClauses, setSelectedClauses, onAddNewStandard, onReferenceClause, showIntegrityModal, setShowIntegrityModal }: SidebarProps) => {
    const [isResizing, setIsResizing] = useState(false);
    const [searchQueryRaw, setSearchQueryRaw] = useState("");
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);

    const searchQuery = useDebounce(searchQueryRaw, 300);

    const startResizing = (e: React.MouseEvent) => {
        if ((e.target as Element).classList.contains('resize-handle')) {
            e.preventDefault();
            setIsResizing(true);
        }
    };

    useEffect(() => {
        const stopResizing = () => setIsResizing(false);
        const resize = (e: MouseEvent) => {
            if (isResizing) {
                const newWidth = Math.max(360, Math.min(e.clientX, 800));
                setWidth(newWidth);
            }
        };
        if (isResizing) {
            window.addEventListener('mousemove', resize);
            window.addEventListener('mouseup', stopResizing);
        }
        return () => {
            window.removeEventListener('mousemove', resize);
            window.removeEventListener('mouseup', stopResizing);
        };
    }, [isResizing, setWidth]);

    const runHealthCheck = () => {
        if (!standardKey || !standards[standardKey]) return { score: 0, items: [] };
        const data = standards[standardKey];
        const items: { label: string, status: 'pass' | 'fail', detail: string }[] = [];
        const allClauses = data.groups.flatMap(g => g.clauses);
        const flatten = (list: Clause[]): Clause[] => {
            return list.reduce((acc, c) => {
                acc.push(c); if (c.subClauses) acc.push(...flatten(c.subClauses)); return acc;
            }, [] as Clause[]);
        };
        const flatList = flatten(allClauses);
        if (standardKey.includes("9001")) {
            ['8.4', '8.6', '8.7', '7.1.4'].forEach(code => {
                const found = flatList.some(c => c.code === code);
                items.push({ label: `Clause ${code}`, status: found ? 'pass' : 'fail', detail: found ? 'Verified' : 'Missing' });
            });
        }
        const missingDesc = flatList.filter(c => !c.description || c.description.length < 5).length;
        items.push({ label: 'Content Quality', status: missingDesc === 0 ? 'pass' : 'fail', detail: missingDesc === 0 ? 'Descriptions OK' : `${missingDesc} incomplete` });
        const score = Math.round((items.filter(i => i.status === 'pass').length / (items.length || 1)) * 100);
        return { score, items };
    };

    const handleCopySelectedClauses = () => {
        if (!standardKey || !standards[standardKey]) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { const f = findClause(id, c.subClauses); if (f) return f; } 
            }
        };
        const allClauses = standards[standardKey].groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses.map(id => findClause(id, allClauses)).filter((c): c is Clause => !!c).map(c => `[${c.code}] ${c.title}`).join('\n');
        copyToClipboard(selectedData);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => {
            let ids = [c.id]; if (c.subClauses) c.subClauses.forEach(sub => ids.push(...getAllIds(sub))); return ids;
        };
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);

        // FIX: Replaced buggy recursive IIFE with a named helper to fix "Property 'some' does not exist" errors.
        const getSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses || item.subClauses.length === 0) {
                const isSel = selectedClauses.includes(item.id);
                return { all: isSel, some: isSel };
            }
            const subRes = item.subClauses.map(getSelectionStatus);
            const all = selectedClauses.includes(item.id) && subRes.every(r => r.all);
            const some = selectedClauses.includes(item.id) || subRes.some(r => r.some);
            return { all, some };
        };
        const selection = getSelectionStatus(c);

        return (
            <div key={c.id} className={`flex flex-col ${level > 0 ? 'ml-4 border-l-2 dark:border-slate-800' : ''}`}>
                <div className={`group flex items-start gap-3 p-2 rounded-xl transition-all cursor-pointer ${isSelected ? 'bg-indigo-50/80 dark:bg-indigo-900/20' : 'hover:bg-gray-100/50 dark:hover:bg-slate-800/50'}`}>
                    <button onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} className={`mt-1 flex-shrink-0 transition-colors ${selection.some ? 'text-indigo-600 dark:text-indigo-400' : 'text-gray-300 dark:text-slate-600'}`}>
                        {selection.all ? <Icon name="CheckSquare" size={16}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={16}/>}
                    </button>
                    <div className="flex-1 min-w-0" onClick={() => hasSubs ? setExpandedClauses(p => p.includes(c.id) ? p.filter(x=>x!==c.id) : [...p, c.id]) : toggleClauseSelection(c)}>
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-center gap-1.5 flex-wrap">
                                <span className="text-[11px] font-bold text-indigo-700 dark:text-indigo-400 uppercase bg-indigo-50 dark:bg-indigo-900/30 px-1 rounded">{c.code}</span>
                                <span className="text-[11px] text-slate-900 dark:text-slate-100 font-extrabold tracking-tight leading-tight">{c.title}</span>
                            </div>
                            <div className="flex gap-1">
                                <button onClick={e=>{e.stopPropagation(); onReferenceClause(c);}} className="opacity-0 group-hover:opacity-100 p-1 hover:text-indigo-600 transition-opacity"><Icon name="BookOpen" size={12}/></button>
                                {hasSubs && <Icon name={isExpanded ? "ChevronUp" : "ChevronDown"} size={12} className="text-gray-400 mt-0.5 shrink-0"/>}
                            </div>
                        </div>
                        <div className="text-[10px] text-slate-500 dark:text-slate-400 italic mt-1.5 border-t border-gray-100 dark:border-slate-800 pt-1">{c.description}</div>
                    </div>
                </div>
                {hasSubs && isExpanded && <div className="mt-1 flex flex-col">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>}
            </div>
        );
    };

    const renderClauses = () => {
        if (!standardKey || !standards[standardKey]) return <div className="text-center text-gray-400 mt-20 italic text-xs">Select a Standard</div>;
        const data = standards[standardKey];
        return data.groups.map(g => {
            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
            return (
                <div key={g.id} className="mb-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm overflow-hidden">
                    <div className="flex items-center justify-between p-3.5 bg-gray-50/50 dark:bg-slate-800/30 cursor-pointer" onClick={() => setExpandedGroups(p => p.includes(g.id) ? p.filter(x=>x!==g.id) : [...p, g.id])}>
                        <div className="flex items-center gap-3">
                            <button className="p-2 rounded-xl shadow-lg text-white bg-slate-800"><Icon name={g.icon} size={14}/></button>
                            <h4 className="text-[10px] font-black uppercase tracking-widest">{g.title}</h4>
                        </div>
                        <Icon name={isGroupExpanded ? "ChevronUp" : "ChevronDown"} size={12}/>
                    </div>
                    {isGroupExpanded && <div className="p-2 space-y-1 bg-white dark:bg-slate-900">{g.clauses.map(c => renderClauseItem(c))}</div>}
                </div>
            );
        });
    };

    const health = runHealthCheck();

    return (
        <div className={`${isOpen ? 'border-r' : 'w-0 border-0 overflow-hidden'} flex flex-col bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-2xl relative shrink-0 transition-[width] duration-300`} style={{ width: isOpen ? width : 0 }}>
             {isOpen && <div className="absolute right-0 top-0 bottom-0 w-1.5 cursor-col-resize hover:bg-indigo-500 z-50 resize-handle" onMouseDown={startResizing} />}
            <div className="p-5 border-b border-gray-100 dark:border-slate-800 min-w-[360px]">
                <div className="space-y-3">
                    <div className="relative">
                        <IconSelect icon="Book" value={standardKey} onChange={(e:any)=>setStandardKey(e.target.value)} options={Object.keys(standards).map(k=>({value:k, label:standards[k].name}))} defaultText="Select Standard" />
                        <button onClick={()=>setShowIntegrityModal(true)} className={`absolute -top-2 -right-2 p-1.5 rounded-full shadow-2xl transition-all text-white ring-4 ring-white dark:ring-slate-900 ${health.score === 100 ? 'bg-emerald-500' : 'bg-orange-500'}`}><Icon name={health.score === 100 ? "CheckCircle2" : "AlertCircle"} size={14}/></button>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <IconInput icon="Building" placeholder="Company" value={auditInfo.company} onChange={(e:any)=>setAuditInfo({...auditInfo, company: e.target.value})} />
                        <IconInput icon="Tag" placeholder="Audit ID" value={auditInfo.smo} onChange={(e:any)=>setAuditInfo({...auditInfo, smo: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <IconInput icon="Users" placeholder="Department" value={auditInfo.department} onChange={(e:any)=>setAuditInfo({...auditInfo, department: e.target.value})} />
                        <IconInput icon="User" placeholder="Auditee" value={auditInfo.interviewee} onChange={(e:any)=>setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                    </div>
                </div>
            </div>
            <div className="flex-1 flex flex-col min-h-0 min-w-[360px]">
                <div className="p-3 border-b border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
                    <div className="flex items-center gap-2">
                        <div className="relative flex-1">
                            <span className="absolute left-3 top-2.5 text-slate-400"><Icon name="Search" size={14}/></span>
                            <input className="w-full pl-9 pr-3 py-2 text-xs bg-gray-100 dark:bg-slate-800 rounded-xl outline-none" placeholder="Search..." value={searchQueryRaw} onChange={e=>setSearchQueryRaw(e.target.value)}/>
                        </div>
                        {selectedClauses.length > 0 && (
                            <button onClick={handleCopySelectedClauses} className="p-2 rounded-xl bg-indigo-50 text-indigo-600 border border-indigo-100"><Icon name="Copy" size={16} /></button>
                        )}
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar p-3">{renderClauses()}</div>
            </div>
            <Modal isOpen={showIntegrityModal} title="Data Health Index" onClose={()=>setShowIntegrityModal(false)}>
                <div className="space-y-6">
                    <div className="flex items-center gap-5 p-5 rounded-3xl bg-gray-50 dark:bg-slate-800 border border-gray-100 dark:border-slate-700">
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center text-white text-2xl font-black ${health.score === 100 ? 'bg-emerald-500' : 'bg-orange-500'}`}>{health.score}%</div>
                        <div className="flex-1">
                            <h4 className="font-black uppercase tracking-tight">Data Integrity</h4>
                            <p className="text-xs text-slate-500">{health.score === 100 ? 'Excellent status.' : 'Incomplete information.'}</p>
                        </div>
                    </div>
                    <div className="space-y-3">
                        {health.items.map((item, idx) => (
                            <div key={idx} className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 border rounded-2xl">
                                <div className="flex items-center gap-4"><Icon name={item.status === 'pass' ? "CheckCircle2" : "AlertCircle"} className={item.status === 'pass' ? 'text-emerald-500' : 'text-red-500'}/><span className="text-sm font-bold">{item.label}</span></div>
                                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${item.status === 'pass' ? 'text-emerald-700 bg-emerald-100' : 'text-red-700 bg-red-100'}`}>{item.detail}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </Modal>
        </div>
    );
};
export default Sidebar;
